from __future__ import annotations
import json
from pathlib import Path
HTML=Path('docs/index.html');DATA=Path('data/dashboard/wnba_cross_market_top_plays.json')
CSS=r'''<style id="v4-top-plays-style">.bbHero{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px;margin:12px 0}.bbKpi{border:1px solid #21314b;border-radius:14px;padding:12px;background:#08101c}.bbKpi b{display:block;font-size:24px}.bbGroup{margin:18px 0}.bbGroupTitle{display:flex;justify-content:space-between;align-items:center;margin-bottom:9px}.bbGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));gap:12px}.bbCard{border:1px solid #21314b;border-radius:16px;padding:15px;background:#0a1322}.bbTop{display:flex;justify-content:space-between;gap:10px}.bbScore{font-size:30px;font-weight:950}.bbTier{font-size:10px;font-weight:950;border:1px solid currentColor;border-radius:999px;padding:4px 8px}.bbElite{color:#00e39b}.bbPremium{color:#7fb3ff}.bbStrong{color:#ffd166}.bbLean{color:#c7a6ff}.bbWatch{color:#8fa0bd}.bbPlay{font-size:18px;font-weight:950;margin:9px 0 3px}.bbMeta{font-size:11px;color:#8fa0bd}.bbMetrics{display:grid;grid-template-columns:repeat(3,1fr);gap:7px;margin:11px 0}.bbMetric{border:1px solid #20304b;border-radius:10px;padding:8px}.bbMetric b{display:block;font-size:15px}.bbWhy{margin-top:10px;border-top:1px solid #20304b;padding-top:9px}.bbWhy summary{cursor:pointer;font-weight:900}.bbComp{display:grid;grid-template-columns:1fr auto;gap:8px;padding:5px 0;font-size:11px}.bbStatus{font-weight:950}.bbBet{color:#00e39b}.bbLeanText{color:#ffd166}.bbWatchText{color:#8fa0bd}.bbEmpty{padding:28px;text-align:center;color:#8fa0bd}</style>'''
SCRIPT=r'''<script id="v4-top-plays-script">(function(){const tierClass=t=>t==='ELITE'?'bbElite':t==='PREMIUM'?'bbPremium':t==='STRONG'?'bbStrong':t==='LEAN'?'bbLean':'bbWatch';const statusClass=d=>d==='BET'?'bbBet':d==='LEAN'?'bbLeanText':'bbWatchText';function card(r){const play=r.player?`${E(r.player)} ${E(r.stat)} ${E(r.side)} ${E(r.line)}`:`${E(r.game)} ${E(r.stat)} ${E(r.side)} ${E(r.line)}`;const c=r.ranking_components||{};const comps=[['Projection edge',c.ev],['Hit probability',c.probability],['Model confidence',c.confidence],['Data quality',c.data_quality],['Price quality',c.price_quality],['CLV history',c.clv_history]].filter(x=>x[1]!=null).map(x=>`<div class="bbComp"><span>${E(x[0])}</span><b class="mono">${E(x[1])}</b></div>`).join('');return `<div class="bbCard"><div class="bbTop"><div><span class="bbTier ${tierClass(r.score_tier)}">${E(r.score_tier||'WATCH')}</span><div class="bbMeta mono">#${E(r.rank)} · ${E(r.market_type)}</div></div><div class="bbScore mono">${E(r.top_play_score)}</div></div><div class="bbPlay">${play}</div><div class="bbMeta mono">${E(r.game||'')} · ${E(r.sportsbook||'—')} ${E(r.odds||'—')}</div><div class="bbMetrics"><div class="bbMetric"><span class="small">Hit</span><b class="mono">${Math.round(Number(r.hit_probability||0)*100)}%</b></div><div class="bbMetric"><span class="small">EV</span><b class="mono">${r.expected_value_per_unit==null?'—':(Number(r.expected_value_per_unit)*100).toFixed(1)+'%'}</b></div><div class="bbMetric"><span class="small">Projection</span><b class="mono">${E(r.projection??'—')}</b></div></div><div class="row"><span class="bbStatus ${statusClass(r.decision)}">${E(r.decision)}</span><span class="mono">Risk ${E(r.risk_level)}</span><span class="mono">Units ${E(r.recommended_units_final??0)}</span></div><details class="bbWhy"><summary>Why this score?</summary>${comps}${r.exposure_penalty?`<div class="bbMeta">Exposure adjustment: ${E(r.exposure_penalty)}</div>`:''}</details></div>`}function group(title,rows){if(!rows.length)return'';return `<div class="bbGroup"><div class="bbGroupTitle"><h3 class="mono">${E(title)}</h3><span class="small mono">${rows.length} plays</span></div><div class="bbGrid">${rows.map(card).join('')}</div></div>`}window.topPlays=function(){const p=DATA.top_plays||{},all=Array.isArray(p.top_plays)?p.top_plays:[];const primary=all.filter(r=>r.decision==='BET');const leans=all.filter(r=>r.decision==='LEAN');const watch=all.filter(r=>r.decision==='WATCH').slice(0,8);const s=p.summary||{};return `<div class="section"><h2 class="mono">Best Bets</h2><div class="small mono">One primary recommendation per player. Scores are calibrated; 99 is reserved for exceptional, fully supported plays.</div><div class="bbHero"><div class="bbKpi"><span>BET</span><b class="mono">${E(s.bets||0)}</b></div><div class="bbKpi"><span>LEAN</span><b class="mono">${E(s.leans||0)}</b></div><div class="bbKpi"><span>ELITE</span><b class="mono">${E(s.elite||0)}</b></div><div class="bbKpi"><span>UNITS</span><b class="mono">${E(s.allocated_units||0)}</b></div></div>${group('Primary Bets',primary)}${group('Leans',leans)}${group('Watchlist',watch)}${!primary.length&&!leans.length?'<div class="bbEmpty mono">No qualified priced recommendations.</div>':''}</div>`};window.best=window.topPlays;})();</script>'''
def replace_block(html,start,end,replacement):
 i=html.find(start)
 if i<0:return html
 j=html.find(end,i)
 if j<0:return html
 return html[:i]+replacement.strip()+html[j+len(end):]
def main():
 if not HTML.exists():raise SystemExit('docs/index.html missing')
 try:payload=json.load(DATA.open(encoding='utf-8')) if DATA.exists() else {}
 except Exception:payload={}
 html=HTML.read_text(encoding='utf-8');data=f'<script id="v4-top-plays-data">DATA.top_plays={json.dumps(payload,separators=(",",":"),ensure_ascii=False)};</script>'
 html=replace_block(html,'<script id="v4-top-plays-data">','</script>',data) if 'id="v4-top-plays-data"' in html else html.replace('</body>',data+'</body>')
 html=replace_block(html,'<style id="v4-top-plays-style">','</style>',CSS) if 'id="v4-top-plays-style"' in html else html.replace('</head>',CSS+'</head>')
 html=replace_block(html,'<script id="v4-top-plays-script">','</script>',SCRIPT) if 'id="v4-top-plays-script"' in html else html.replace('</body>',SCRIPT+'</body>')
 HTML.write_text(html,encoding='utf-8');print('Best Bets restructured with calibrated tiers')
if __name__=='__main__':main()
